// reloadStatusFileName is the name of the file, stored under the TSDB storage
// directory, that holds the persisted outcome of the most recent transactional
// configuration reload attempt.
const reloadStatusFileName = "reload_status.json"

// reloadTransactionManager runs configuration reloaders transactionally: it
// applies reloaders in sequence, stopping and rolling back to the last
// known-good configuration if a reloader fails partway through. It also
// records the outcome of the most recent attempt, both in memory (for the
// HTTP API) and on disk (so it survives restarts).
type reloadTransactionManager struct {
	enabled bool
	path    string
	logger  *slog.Logger

	mu           sync.Mutex
	status       api_v1.ReloadStatus
	lastGoodConf *config.Config
}

func newReloadTransactionManager(enabled bool, storageDir string, logger *slog.Logger) *reloadTransactionManager {
	return &reloadTransactionManager{
		enabled: enabled,
		path:    filepath.Join(storageDir, reloadStatusFileName),
		logger:  logger,
		status: api_v1.ReloadStatus{
			ErrorCategory:     api_v1.ReloadErrorCategoryNone,
			AppliedReloaders:  []string{},
			ReloaderTimingsMs: map[string]int64{},
		},
	}
}

// loadPersisted best-effort loads a previously persisted reload outcome from
// disk. A missing or corrupted file must not prevent startup, so any error is
// logged and otherwise ignored.
func (m *reloadTransactionManager) loadPersisted() {
	data, err := os.ReadFile(m.path)
	if err != nil {
		if !os.IsNotExist(err) {
			m.logger.Warn("Failed to read persisted reload status, ignoring", "file", m.path, "err", err)
		}
		return
	}

	var status api_v1.ReloadStatus
	if err := json.Unmarshal(data, &status); err != nil {
		m.logger.Warn("Failed to parse persisted reload status, ignoring", "file", m.path, "err", err)
		return
	}

	m.mu.Lock()
	defer m.mu.Unlock()
	m.status = status
}

// APIStatus returns the current reload status, for the HTTP API.
func (m *reloadTransactionManager) APIStatus() api_v1.ReloadStatus {
	m.mu.Lock()
	defer m.mu.Unlock()
	return m.status
}

func (m *reloadTransactionManager) setLastGoodConfig(conf *config.Config) {
	m.mu.Lock()
	defer m.mu.Unlock()
	m.lastGoodConf = conf
}

func (m *reloadTransactionManager) getLastGoodConfig() *config.Config {
	m.mu.Lock()
	defer m.mu.Unlock()
	return m.lastGoodConf
}

// record updates the in-memory status and persists it to disk, best-effort.
func (m *reloadTransactionManager) record(status api_v1.ReloadStatus) {
	m.mu.Lock()
	m.status = status
	m.mu.Unlock()

	data, err := json.Marshal(status)
	if err != nil {
		m.logger.Warn("Failed to marshal reload status for persistence", "err", err)
		return
	}

	if err := os.MkdirAll(filepath.Dir(m.path), 0o777); err != nil {
		m.logger.Warn("Failed to create directory for reload status persistence", "dir", filepath.Dir(m.path), "err", err)
		return
	}

	tmp := m.path + ".tmp"
	if err := os.WriteFile(tmp, data, 0o644); err != nil {
		m.logger.Warn("Failed to persist reload status", "file", m.path, "err", err)
		return
	}
	if err := os.Rename(tmp, m.path); err != nil {
		m.logger.Warn("Failed to persist reload status", "file", m.path, "err", err)
	}
}

// applyReloaders runs rls in sequence against conf, stopping at the first
// failure. It returns the names of the reloaders that applied successfully,
// their individual timings, and the name of the reloader that failed (if
// any).
func applyReloaders(conf *config.Config, rls []reloader) (applied []string, timings map[string]int64, failedReloader string, err error) {
	applied = []string{}
	timings = make(map[string]int64, len(rls))
	for _, rl := range rls {
		rstart := time.Now()
		rerr := rl.reloader(conf)
		timings[rl.name] = time.Since(rstart).Milliseconds()
		if rerr != nil {
			return applied, timings, rl.name, fmt.Errorf("failed to apply configuration for %s: %w", rl.name, rerr)
		}
		applied = append(applied, rl.name)
	}
	return applied, timings, "", nil
}

