type reloadStatusResponse struct {
	Status string              `json:"status"`
	Data   api_v1.ReloadStatus `json:"data"`
}

func getReloadStatus(t *testing.T, baseURL string) api_v1.ReloadStatus {
	t.Helper()

	resp, err := http.Get(baseURL + "/api/v1/status/reload")
	require.NoError(t, err)
	defer resp.Body.Close()
	require.Equal(t, http.StatusOK, resp.StatusCode)

	body, err := io.ReadAll(resp.Body)
	require.NoError(t, err)

	var out reloadStatusResponse
	require.NoError(t, json.Unmarshal(body, &out))
	require.Equal(t, "success", out.Status)
	return out.Data
}

func waitReady(t *testing.T, baseURL string) {
	t.Helper()
	require.Eventually(t, func() bool {
		resp, err := http.Get(baseURL + "/-/ready")
		if err != nil {
			return false
		}
		defer resp.Body.Close()
		return resp.StatusCode == http.StatusOK
	}, 10*time.Second, 100*time.Millisecond, "Prometheus didn't become ready in time")
}

// TestTransactionalReload_DisabledByDefault verifies that without the
// transactional-reload-config feature flag, the reload status endpoint keeps
// reporting the "never reloaded" defaults, and no state file is written.
func TestTransactionalReload_DisabledByDefault(t *testing.T) {
	dataDir := t.TempDir()
	configDir := t.TempDir()
	configFilePath := filepath.Join(configDir, "prometheus.yml")
	require.NoError(t, os.WriteFile(configFilePath, []byte("global:\n  scrape_interval: 30s\n"), 0o644))

	port := testutil.RandomUnprivilegedPort(t)
	prom := prometheusCommandWithLogging(t, configFilePath, port, "--storage.tsdb.path="+dataDir)
	require.NoError(t, prom.Start())

	baseURL := "http://localhost:" + strconv.Itoa(port)
	waitReady(t, baseURL)

	status := getReloadStatus(t, baseURL)
	require.Equal(t, "", status.LastReloadID)
	require.False(t, status.LastReloadSuccessful)
	require.Equal(t, api_v1.ReloadErrorCategoryNone, status.ErrorCategory)

	require.NoFileExists(t, filepath.Join(dataDir, reloadStatusFileName))
}

